# Phytron MCC-1 MINI-W-ETH StreamDevice protocol file
#
# Communication notes:
# - Verified framing from captures: STX=0x02, ETX=0x03
# - Verified observed TX example: 02 30 58 50 32 30 52 03  -> "0XP20R"
# - Verified observed RX example: 02 06 31 30 30 03
# - Address handling is critical during commissioning.
#   Previous non-working setup used address '1'; observed working setup used address '0'.
# - This scaffold currently hardcodes address '0' in payloads because only that working
#   case is presently evidenced. If your controller is configured differently, adjust the
#   address byte in each payload below and re-test.
#
# Verification status by block:
# - getPosition : partially verified payload/style (based on observed traffic)
# - getSpeed    : payload placeholder in MCC-1 frame style, must be verified on hardware
# - movePlus    : payload placeholder in MCC-1 frame style, must be verified on hardware
# - moveMinus   : payload placeholder in MCC-1 frame style, must be verified on hardware
# - stopMotion  : payload placeholder in MCC-1 frame style, must be verified on hardware

Terminator = "";
ExtraInput = Ignore;
ReadTimeout = 1000;
ReplyTimeout = 1000;
LockTimeout = 5000;

# Common reply shape currently assumed from capture:
#   STX + 1 status/control byte + ASCII numeric payload + ETX
# Example observed RX: 02 06 31 30 30 03
# The leading 0x06 is treated as a control/status byte and ignored for now.
getPosition {
    # Partially verified command bytes from capture:
    #   \x02 30 58 50 32 30 52 \x03  ==  STX '0XP20R' ETX
    # Address handling check:
    #   The leading ASCII '0' is the currently assumed MCC-1 address.
    #   Change to '1' or other configured address only if commissioning proves it.
    out "\x0230XP20R\x03";
    in  "\x02%*c%d\x03";
}

getSpeed {
    # Placeholder payload in framed MCC-1 style.
    # Bytes below are NOT verified by capture and must be checked during commissioning.
    # Current payload candidate: '0XV20R'
    # Address handling check: the leading ASCII '0' may need adjustment.
    out "\x0230XV20R\x03";
    in  "\x02%*c%d\x03";
}

movePlus {
    # Placeholder payload in framed MCC-1 style.
    # Bytes below are NOT verified by capture and must be checked during commissioning.
    # Current payload candidate: '0XP21R'
    # Address handling check: the leading ASCII '0' may need adjustment.
    out "\x0230XP21R\x03";
    # No reply parser yet: actual ACK/response format is still unverified.
    @mismatch { }
}

moveMinus {
    # Placeholder payload in framed MCC-1 style.
    # Bytes below are NOT verified by capture and must be checked during commissioning.
    # Current payload candidate: '0XP22R'
    # Address handling check: the leading ASCII '0' may need adjustment.
    out "\x0230XP22R\x03";
    # No reply parser yet: actual ACK/response format is still unverified.
    @mismatch { }
}

stopMotion {
    # Placeholder payload in framed MCC-1 style.
    # Bytes below are NOT verified by capture and must be checked during commissioning.
    # Current payload candidate: '0XH'
    # Address handling check: the leading ASCII '0' may need adjustment.
    out "\x0230XH\x03";
    # No reply parser yet: actual ACK/response format is still unverified.
    @mismatch { }
}
